                  if "buildingStartDate" in data:
                      parts.append(f"construction began in {data.pop('buildingStartDate')}")
                  if "completionDate" in data:
                      parts.append(f"was completed in {data.pop('completionDate')}")

              # Floor count
              if "floorCount" in data:
                  parts.append(f"has {data.pop('floorCount')} floors")

